+    flags: c_int,
+    mode: c_uint,
+) -> c_int {
+    unsafe { libc::syscall(libc::SYS_openat, libc::AT_FDCWD, pathname, flags, mode) as c_int }
+}
+
+/// `__open64_nocancel` — open64 without cancellation point (same as __open_nocancel on 64-bit).
